<script setup lang="ts">
import { ref } from 'vue'
import { Eye, EyeOff, Lock, MessageSquare, Mail, Phone } from 'lucide-vue-next'
import { useRouter } from 'vue-router'

const router = useRouter()

const formData = ref({
  phone: '',
  password: '',
  confirmPassword: '',
  captcha: '',
  email: '',
})

const showPassword = ref(false)
const showConfirmPassword = ref(false)
const isLoading = ref(false)
const errorMessage = ref('')

const validateForm = () => {
  if (!formData.value.phone.trim()) {
    errorMessage.value = '请输入手机号'
    return false
  }
  if (!/^1[3-9]\d{9}$/.test(formData.value.phone)) {
    errorMessage.value = '请输入有效的手机号码'
    return false
  }
  if (!formData.value.password) {
    errorMessage.value = '请输入密码'
    return false
  }
  if (formData.value.password.length < 6) {
    errorMessage.value = '密码长度不能少于6位'
    return false
  }
  if (formData.value.password !== formData.value.confirmPassword) {
    errorMessage.value = '两次输入的密码不一致'
    return false
  }
  if (!formData.value.captcha) {
    errorMessage.value = '请输入验证码'
    return false
  }
  if (formData.value.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.value.email)) {
    errorMessage.value = '请输入有效的邮箱地址'
    return false
  }
  errorMessage.value = ''
  return true
}

const handleRegister = async () => {
  if (!validateForm()) return
  
  isLoading.value = true
  errorMessage.value = ''
  
  try {
    const response = await fetch('/api/v1/user/register', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        username: formData.value.phone,
        password: formData.value.password,
        phone: formData.value.phone,
        email: formData.value.email,
      }),
    })
    
    const result = await response.json()
    
    if (result.code === 0) {
      localStorage.setItem('user', JSON.stringify(result.data))
      router.push('/')
    } else {
      errorMessage.value = result.msg || '注册失败'
    }
  } catch (error) {
    errorMessage.value = '注册失败，请稍后重试'
  } finally {
    isLoading.value = false
  }
}
</script>

<template>
  <div class="min-h-screen bg-gradient-to-br from-flame-50 via-white to-orange-50 dark:from-dark-700 dark:to-dark-600 relative overflow-hidden">
    <div class="absolute top-0 left-0 w-full h-full">
      <div class="absolute top-1/4 -left-32 w-96 h-96 bg-flame-400/10 rounded-full blur-3xl"></div>
      <div class="absolute bottom-1/4 -right-32 w-96 h-96 bg-orange-400/10 rounded-full blur-3xl"></div>
      <div class="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-gradient-to-br from-flame-500/5 to-transparent rounded-full blur-3xl"></div>
    </div>

    <div class="relative z-10 min-h-screen flex flex-col">
      <header class="flex items-center justify-between px-6 lg:px-12 py-6">
        <router-link to="/" class="flex items-center gap-3 group">
          <img src="/logo.png" alt="火焰云" class="w-10 h-10 group-hover:opacity-80 transition-opacity" />
          <span class="text-xl font-bold text-gray-900 dark:text-white">火焰云</span>
        </router-link>
        <nav class="hidden md:flex items-center gap-8">
          <a href="/" class="text-gray-600 hover:text-flame-500 dark:text-gray-300 dark:hover:text-flame-400 transition-colors">首页</a>
          <a href="/cloudService/ecs" class="text-gray-600 hover:text-flame-500 dark:text-gray-300 dark:hover:text-flame-400 transition-colors">产品服务</a>
          <a href="/solution" class="text-gray-600 hover:text-flame-500 dark:text-gray-300 dark:hover:text-flame-400 transition-colors">解决方案</a>
          <a href="/about" class="text-gray-600 hover:text-flame-500 dark:text-gray-300 dark:hover:text-flame-400 transition-colors">关于我们</a>
        </nav>
      </header>

      <main class="flex-1 flex items-center justify-center px-4 py-12 lg:py-20">
        <div class="w-full max-w-md">
          <div class="text-center mb-10">
            <h1 class="text-3xl font-bold text-gray-900 dark:text-white mb-4">用户注册</h1>
            <p class="text-gray-500 dark:text-gray-400">创建您的账户，开始体验云端服务</p>
          </div>

          <div class="bg-white dark:bg-dark-500/80 backdrop-blur-lg rounded-2xl shadow-xl shadow-gray-200/50 dark:shadow-black/20 p-8 border border-gray-100 dark:border-white/10">
            <form @submit.prevent="handleRegister" class="space-y-5">
              <div v-if="errorMessage" class="mb-4">
                <div class="flex items-center gap-2 px-4 py-3 bg-red-50 border border-red-200 rounded-lg text-red-600 dark:bg-red-500/10 dark:border-red-500/30 dark:text-red-400">
                  <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                  </svg>
                  {{ errorMessage }}
                </div>
              </div>

              <div class="relative">
                <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                  <Phone class="w-5 h-5" />
                </div>
                <input
                  v-model="formData.phone"
                  type="tel"
                  placeholder="手机号"
                  class="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
                />
              </div>

              <div class="relative">
                <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                  <Lock class="w-5 h-5" />
                </div>
                <input
                  v-model="formData.password"
                  :type="showPassword ? 'text' : 'password'"
                  placeholder="密码"
                  class="w-full pl-12 pr-12 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
                />
                <button
                  type="button"
                  @click="showPassword = !showPassword"
                  class="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 transition-colors"
                >
                  <Eye v-if="showPassword" class="w-5 h-5" />
                  <EyeOff v-else class="w-5 h-5" />
                </button>
              </div>

              <div class="relative">
                <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                  <Lock class="w-5 h-5" />
                </div>
                <input
                  v-model="formData.confirmPassword"
                  :type="showConfirmPassword ? 'text' : 'password'"
                  placeholder="确认密码"
                  class="w-full pl-12 pr-12 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
                />
                <button
                  type="button"
                  @click="showConfirmPassword = !showConfirmPassword"
                  class="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 transition-colors"
                >
                  <Eye v-if="showConfirmPassword" class="w-5 h-5" />
                  <EyeOff v-else class="w-5 h-5" />
                </button>
              </div>

              <div class="relative">
                <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                  <MessageSquare class="w-5 h-5" />
                </div>
                <input
                  v-model="formData.captcha"
                  type="text"
                  placeholder="验证码"
                  class="w-full pl-12 pr-28 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
                />
                <button
                  type="button"
                  class="absolute right-2 top-1/2 -translate-y-1/2 px-3 py-2 bg-gray-100 hover:bg-gray-200 dark:bg-dark-300 dark:hover:bg-dark-200 rounded-lg text-sm text-gray-600 dark:text-gray-300 transition-colors"
                >
                  获取验证码
                </button>
              </div>

              <div class="relative">
                <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                  <Mail class="w-5 h-5" />
                </div>
                <input
                  v-model="formData.email"
                  type="email"
                  placeholder="邮箱（选填）"
                  class="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
                />
              </div>

              <div class="flex items-start gap-2">
                <input
                  type="checkbox"
                  id="agree"
                  class="mt-1 w-4 h-4 text-flame-500 border-gray-300 rounded focus:ring-flame-500 dark:bg-dark-400 dark:border-dark-300"
                />
                <label for="agree" class="text-sm text-gray-500 dark:text-gray-400">
                  我已阅读并同意<a href="#" class="text-flame-500 hover:text-flame-600 dark:text-flame-400 transition-colors">《用户协议》</a>和<a href="#" class="text-flame-500 hover:text-flame-600 dark:text-flame-400 transition-colors">《隐私政策》</a>
                </label>
              </div>

              <button
                type="submit"
                :disabled="isLoading"
                class="w-full bg-gradient-to-r from-flame-500 to-orange-500 text-white py-4 rounded-xl font-semibold text-base hover:shadow-lg hover:shadow-flame-500/25 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <span v-if="isLoading" class="flex items-center justify-center gap-2">
                  <span class="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                  注册中...
                </span>
                <span v-else>立即注册</span>
              </button>
            </form>

            <div class="mt-6 pt-6 border-t border-gray-100 dark:border-white/10">
              <p class="text-center text-sm text-gray-500 dark:text-gray-400">
                已有账户？
                <router-link to="/login" class="text-flame-500 hover:text-flame-600 dark:text-flame-400 font-medium transition-colors">立即登录</router-link>
              </p>
            </div>
          </div>

          <p class="mt-8 text-center text-sm text-gray-400 dark:text-gray-500">
            © 2024 火焰云. 保留所有权利.
          </p>
        </div>
      </main>
    </div>
  </div>
</template>
