<script setup lang="ts">
import { ref, computed } from 'vue'
import { Search, Server, Globe, Database, Shield } from 'lucide-vue-next'

const searchQuery = ref('')
const activeCategory = ref('ecs')

const categories = [
  { id: 'ecs', name: '云服务器', icon: Server },
  { id: 'cdn', name: 'CDN', icon: Globe },
  { id: 'oss', name: 'OSS', icon: Database },
  { id: 'gfip', name: '高防IP', icon: Shield },
]

interface DocItem {
  title: string
  category: string
  path: string
}

const allDocs: DocItem[] = [
  { title: '什么是云服务器ECS', category: 'ecs', path: '#' },
  { title: '产品优势', category: 'ecs', path: '#' },
  { title: '基本概念', category: 'ecs', path: '#' },
  { title: '创建实例', category: 'ecs', path: '#' },
  { title: '启动实例', category: 'ecs', path: '#' },
  { title: '停止实例', category: 'ecs', path: '#' },
  { title: '重启实例', category: 'ecs', path: '#' },
  { title: '重装系统', category: 'ecs', path: '#' },
  { title: '创建系统快照', category: 'ecs', path: '#' },
  { title: '续费包年包月实例', category: 'ecs', path: '#' },
  { title: '设置自动续费', category: 'ecs', path: '#' },
  { title: '升级规格', category: 'ecs', path: '#' },
  { title: '磁盘扩容', category: 'ecs', path: '#' },
  { title: '新增数据盘', category: 'ecs', path: '#' },
  { title: '创建私有网络', category: 'ecs', path: '#' },
  { title: '挂在私有网络', category: 'ecs', path: '#' },
  { title: '升级带宽', category: 'ecs', path: '#' },
  { title: '安全组', category: 'ecs', path: '#' },
  { title: '产品优势', category: 'cdn', path: '#' },
  { title: '基本概念', category: 'cdn', path: '#' },
  { title: '什么是CDN', category: 'cdn', path: '#' },
  { title: '产品优势', category: 'oss', path: '#' },
  { title: '基本概念', category: 'oss', path: '#' },
  { title: '什么是OSS', category: 'oss', path: '#' },
  { title: '产品优势', category: 'gfip', path: '#' },
  { title: '基本概念', category: 'gfip', path: '#' },
  { title: '什么是高防IP', category: 'gfip', path: '#' },
  { title: '常见问题', category: 'gfip', path: '#' },
]

const filteredDocs = computed(() => {
  let docs = allDocs
  if (searchQuery.value) {
    const q = searchQuery.value.toLowerCase()
    docs = docs.filter(d => d.title.toLowerCase().includes(q))
  } else {
    docs = docs.filter(d => d.category === activeCategory.value)
  }
  return docs
})

const searchResults = computed(() => searchQuery.value.length > 0)

const groupedDocs = computed(() => {
  if (!searchResults.value) return {}
  const groups: Record<string, DocItem[]> = {}
  filteredDocs.value.forEach(doc => {
    if (!groups[doc.category]) groups[doc.category] = []
    groups[doc.category].push(doc)
  })
  return groups
})

const categoryNameMap: Record<string, string> = {
  ecs: '云服务器',
  cdn: 'CDN',
  oss: 'OSS',
  gfip: '高防IP',
}
</script>

<template>
  <div class="min-h-screen pt-20 lg:pt-24">
    <!-- Hero -->
    <section class="relative overflow-hidden">
      <div class="absolute inset-0 bg-hero-gradient dark:bg-hero-gradient-dark"></div>
      <div class="absolute top-1/3 left-1/3 w-80 h-80 bg-flame-500/10 rounded-full blur-3xl"></div>
      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-20">
        <div class="max-w-2xl mx-auto text-center">
          <h1 class="text-3xl lg:text-4xl font-bold text-white mb-4">文档中心</h1>
          <p class="text-white/70 mb-8">查找产品文档、API参考和操作指南</p>
          <div class="relative">
            <Search class="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              v-model="searchQuery"
              type="text"
              placeholder="搜索文档..."
              class="w-full pl-12 pr-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-white/50 focus:outline-none focus:border-flame-500/50 focus:bg-white/15 transition-all"
            />
          </div>
        </div>
      </div>
    </section>

    <!-- Content -->
    <section class="section-padding">
      <div class="max-w-7xl mx-auto">
        <div class="flex flex-col lg:flex-row gap-8">
          <!-- Sidebar -->
          <div class="lg:w-56 shrink-0">
            <nav class="space-y-1">
              <button
                v-for="cat in categories"
                :key="cat.id"
                :class="[
                  'w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all duration-200',
                  activeCategory === cat.id && !searchResults
                    ? 'bg-flame-50 text-flame-600 dark:bg-flame-500/10 dark:text-flame-400'
                    : 'text-gray-600 hover:bg-gray-50 dark:text-gray-400 dark:hover:bg-white/5',
                ]"
                @click="activeCategory = cat.id; searchQuery = ''"
              >
                <component :is="cat.icon" class="w-4 h-4" />
                {{ cat.name }}
              </button>
            </nav>
          </div>

          <!-- Doc List -->
          <div class="flex-1">
            <div v-if="!searchResults">
              <h2 class="text-xl font-bold text-gray-900 dark:text-white mb-6">{{ categoryNameMap[activeCategory] }}</h2>
              <div class="space-y-2">
                <a
                  v-for="doc in filteredDocs"
                  :key="doc.title"
                  :href="doc.path"
                  class="flex items-center gap-3 p-4 rounded-lg hover:bg-gray-50 dark:hover:bg-white/5 transition-colors group"
                >
                  <span class="w-1.5 h-1.5 rounded-full bg-flame-500 shrink-0"></span>
                  <span class="text-gray-700 dark:text-gray-200 group-hover:text-flame-500 transition-colors">{{ doc.title }}</span>
                </a>
              </div>
            </div>

            <div v-else>
              <h2 class="text-xl font-bold text-gray-900 dark:text-white mb-6">
                搜索结果 "{{ searchQuery }}"（{{ filteredDocs.length }} 条）
              </h2>
              <div v-if="filteredDocs.length === 0" class="text-center py-12">
                <p class="text-gray-500 dark:text-gray-400">未找到相关文档</p>
              </div>
              <div v-else class="space-y-6">
                <div v-for="(docs, catId) in groupedDocs" :key="catId">
                  <h3 class="text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-3">{{ categoryNameMap[catId] }}</h3>
                  <div class="space-y-2">
                    <a
                      v-for="doc in docs"
                      :key="doc.title"
                      :href="doc.path"
                      class="flex items-center gap-3 p-4 rounded-lg hover:bg-gray-50 dark:hover:bg-white/5 transition-colors group"
                    >
                      <span class="w-1.5 h-1.5 rounded-full bg-flame-500 shrink-0"></span>
                      <span class="text-gray-700 dark:text-gray-200 group-hover:text-flame-500 transition-colors">{{ doc.title }}</span>
                    </a>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  </div>
</template>
