import { createRouter, createWebHistory } from 'vue-router'
import HomePage from '@/pages/HomePage.vue'
import EcsPage from '@/pages/EcsPage.vue'
import CdnPage from '@/pages/CdnPage.vue'
import OssPage from '@/pages/OssPage.vue'
import IdcPage from '@/pages/IdcPage.vue'
import AboutPage from '@/pages/AboutPage.vue'
import SolutionPage from '@/pages/SolutionPage.vue'
import EducationPage from '@/pages/solution/EducationPage.vue'
import CommercePage from '@/pages/solution/CommercePage.vue'
import GamePage from '@/pages/solution/GamePage.vue'
import MedicalPage from '@/pages/solution/MedicalPage.vue'
import DocPage from '@/pages/DocPage.vue'
import JoinPage from '@/pages/JoinPage.vue'
import LoginPage from '@/pages/LoginPage.vue'
import RegisterPage from '@/pages/RegisterPage.vue'

const routes = [
  { path: '/', name: 'home', component: HomePage },
  { path: '/cloudService/ecs', name: 'ecs', component: EcsPage },
  { path: '/cloudService/cdn', name: 'cdn', component: CdnPage },
  { path: '/cloudService/oss', name: 'oss', component: OssPage },
  { path: '/idc', name: 'idc', component: IdcPage },
  { path: '/about', name: 'about', component: AboutPage },
  { path: '/solution', name: 'solution', component: SolutionPage },
  { path: '/solution/education', name: 'solution-education', component: EducationPage },
  { path: '/solution/commerce', name: 'solution-commerce', component: CommercePage },
  { path: '/solution/game', name: 'solution-game', component: GamePage },
  { path: '/solution/medical', name: 'solution-medical', component: MedicalPage },
  { path: '/doc', name: 'doc', component: DocPage },
  { path: '/join', name: 'join', component: JoinPage },
  { path: '/login', name: 'login', component: LoginPage },
  { path: '/register', name: 'register', component: RegisterPage },
]

const router = createRouter({
  history: createWebHistory(),
  routes,
})

export default router
