    image: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=cloud%20computing%20server%20room%20blue%20technology%20background%20modern%20clean&image_size=landscape_16_9',
    title: '新用户首购享免费福利',
