    description: '咨询专属销售客服立即领取活动福利',
  },
  {
    image: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=cyber%20security%20shield%20protection%20dark%20blue%20technology%20background&image_size=landscape_16_9',
    title: '玄武盾DDoS防护',
    subtitle: '全球安全加速服务',
    description: '毫秒级攻击响应、多维度行为分析及机器学习',
  },
  {
    image: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=global%20network%20infrastructure%20data%20center%20world%20map%20technology&image_size=landscape_16_9',
